generated_oml:
// C3: Physical sensing components
instance MotorCurrentSensor : DTDFVocab:SensingComponent [
    base:desc "Motor current measurement I_M from Siemens SINUMERIK 840D controller"
    DTDFVocab:producedData MotorCurrentDataTransmitted
]

instance MotorEncoderSensor : DTDFVocab:SensingComponent [
    base:desc "Motor position encoder mounted on the permanent‑magnet synchronous motor"
    DTDFVocab:producedData MotorEncoderDataTransmitted
]

instance GearboxEncoderSensor : DTDFVocab:SensingComponent [
    base:desc "Secondary position encoder located behind the gearwheel gearbox"
    DTDFVocab:producedData GearboxEncoderDataTransmitted
]

// C4: Physical-to-virtual interaction (Data transmitted)
instance MotorCurrentDataTransmitted : DTDFVocab:DataTransmitted [
    DTDFVocab:producedFrom MotorCurrentSensor
]

instance MotorEncoderDataTransmitted : DTDFVocab:DataTransmitted [
    DTDFVocab:producedFrom MotorEncoderSensor
]

instance GearboxEncoderDataTransmitted : DTDFVocab:DataTransmitted [
    DTDFVocab:producedFrom GearboxEncoderSensor
]

// C10: Data stored in the digital shadow
instance MotorCurrentData : DTDFVocab:Data [
    base:desc "Time‑series of motor current I_M stored as floating‑point array in the digital shadow"
    DTDFVocab:fromData MotorCurrentDataTransmitted
    DTDFVocab:inputTo MqttBroker
]

instance MotorAngleData : DTDFVocab:Data [
    base:desc "Time‑series of motor angle r_M transmitted over MQTT and stored in the digital shadow"
    DTDFVocab:fromData MotorEncoderDataTransmitted
    DTDFVocab:inputTo MqttBroker
]

instance GearboxAngleData : DTDFVocab:Data [
    base:desc "Time‑series of gearbox output angle r_G transmitted over MQTT and stored in the digital shadow"
    DTDFVocab:fromData GearboxEncoderDataTransmitted
    DTDFVocab:inputTo MqttBroker
]

// C11: Enablers
instance MqttBroker : DTDFVocab:Enabler [
    base:desc "MQTT broker used for live one‑way streaming of sensor traces to the digital shadow"
    DTDFVocab:enables RealTimeVisualizationService, FrictionIdentificationService
]

instance MatlabSimulinkEngine : DTDFVocab:Enabler [
    base:desc "MATLAB Simulink environment executing executable models of motor, gearbox and friction for simulation and parameter identification"
    DTDFVocab:enables FrictionIdentificationService, FrictionParameterUpdateService
]

instance AssetAdministrationShell : DTDFVocab:Enabler [
    base:desc "Asset Administration Shell providing standardized representation of engineering and simulation models within the digital twin"
    DTDFVocab:enables ModelRepositoryService
]

instance DashboardApp : DTDFVocab:Enabler [
    base:desc "Operator dashboard visualizing real‑time data and insights"
    DTDFVocab:enables RealTimeVisualizationService
]

// C6: Services
instance RealTimeVisualizationService : DTDFVocab:Service [
    base:desc "Real‑time visualization of current, angle, torque and velocity traces in operator dashboard"
    DTDFVocab:provides FrictionLossInsight, MotionAccuracyInsight
]

instance FrictionIdentificationService : DTDFVocab:Service [
    base:desc "Identification of static, kinetic and viscous friction parameters in the gearboxes using simulation models"
    DTDFVocab:provides FrictionParameterInsight
]

instance FrictionParameterUpdateService : DTDFVocab:Service [
    base:desc "Generation and delivery of updated friction model parameters to the robot controller for improved motion accuracy"
    DTDFVocab:provides UpdateFrictionParametersAction
]

instance ModelRepositoryService : DTDFVocab:Service [
    base:desc "Management and access to SysML and Simulink models via Asset Administration Shell"
    DTDFVocab:provides ModelAvailabilityInsight
]

// C17: Insights and Actions
instance FrictionLossInsight : DTDFVocab:Insight [
    base:desc "Insight into friction losses within the gearbox revealed by identified parameters"
]

instance MotionAccuracyInsight : DTDFVocab:Insight [
    base:desc "Insight that updated friction parameters improve robot motion accuracy"
]

instance FrictionParameterInsight : DTDFVocab:Insight [
    base:desc "Insight on static, kinetic and viscous friction characteristics identified for the gearbox"
]

instance UpdateFrictionParametersAction : DTDFVocab:Action [
    base:desc "Automatic update of friction model parameters sent back to the Siemens controller"
    DTDFVocab:IsAutomatic true
]

instance ModelAvailabilityInsight : DTDFVocab:Insight [
    base:desc "Visibility of engineering and simulation models stored in the Asset Administration Shell"
]

// C10: Models
instance SysMLAxisModel : DTDFVocab:Model [
    base:desc "SysML block definition and internal block diagram of the first axis of MABI MAX 100 robot"
    DTDFVocab:inputTo AssetAdministrationShell
]

instance SimulinkMotorModel : DTDFVocab:Model [
    base:desc "MATLAB Simulink executable model of the permanent‑magnet synchronous motor"
    DTDFVocab:inputTo MatlabSimulinkEngine
]

instance SimulinkGearboxModel : DTDFVocab:Model [
    base:desc "MATLAB Simulink executable model of the gearwheel and cycloidal gearbox"
    DTDFVocab:inputTo MatlabSimulinkEngine
]

instance CoulombViscousFrictionModel : DTDFVocab:Model [
    base:desc "Friction model combining Coulomb and viscous components used in simulation"
    DTDFVocab:inputTo MatlabSimulinkEngine
]

instance StribeckFrictionModel : DTDFVocab:Model [
    base:desc "Stribeck friction model for static‑to‑kinetic transition used in simulation"
    DTDFVocab:inputTo MatlabSimulinkEngine
]

instance DahlFrictionModel : DTDFVocab:Model [
    base:desc "Dahl friction model representing pre‑sliding behavior used in simulation"
    DTDFVocab:inputTo MatlabSimulinkEngine
]

instance LuGreFrictionModel : DTDFVocab:Model [
    base:desc "LuGre friction model used for detailed friction dynamics in simulation"
    DTDFVocab:inputTo MatlabSimulinkEngine
]

instance twinning_time_scale : DTDFVocab:TimeScale [
    base:desc "Real‑time operation during robot motion; data are captured continuously while the robot is running (no discrete sampling rate specified)."
]

instance dt_constellation : DTDFVocab:Constellation [
    base:desc "A digital shadow consisting of a Purpose (FrictionDerivation), an Asset (the first axis), Sources (sensor channels), Processing components (Simulation M, GW, GB) that consume input traces and produce simulated traces, and DataTraces/DataPoints organized according to the Digital Shadow Reference Model."
]

instance life_cycle_stages : DTDFVocab:EvolutionStage [
    base:desc "Operative phase – the digital shadow is created and used while the robot is operating to derive friction and refine control."
]

instance fidelity_and_validity_considerations : DTDFVocab:FidelityConsideration [
    base:desc "Full traceability of each data point to its source and processing model; comparison of simulated friction‑free and friction‑included models with measured reference data to assess model accuracy; multi‑physics aware identification of friction."
]

instance dt_technical_connection : DTDFVocab:TechnicalConnection [
    base:desc "One‑way communication using MQTT; data flows from the physical robot to the digital shadow; the shadow is linked to the physical asset via Asset Administration Shells."
]

instance standardization : DTDFVocab:Standardization [
    base:desc "The implementation follows the Asset Administration Shell (AAS) standard for digital twin data encapsulation and uses SysML, a widely adopted MBSE modeling language, to describe engineering models of the robot."
]
